const { Manifold, CrossSection, label, labeledUnion, setCircularSegments } = api;
setCircularSegments(48);

// Helper: box from min..max
function box(min, max) {
  const s = [max[0] - min[0], max[1] - min[1], max[2] - min[2]];
  const c = [(min[0] + max[0]) / 2, (min[1] + max[1]) / 2, (min[2] + max[2]) / 2];
  return Manifold.cube(s, true).translate(c);
}

// --- Balloon envelope: sphere scaled to be taller, then sliced into vertical gores ---
// Sphere: r=10, centered at z=20
// Scale taller: 1.3x in Z
const envR = 10;
const envCX = 0,
  envCY = 0,
  envCZ = 20;

// Base sphere
const baseSphere = Manifold.sphere(envR, 48).scale([1, 1, 1.3]).translate([envCX, envCY, envCZ]);

// 6 gores: each is a wedge of 60 degrees
// Colors cycle: red, yellow, blue, red, yellow, blue
const goreColors = ['red', 'yellow', 'blue', 'red2', 'yellow2', 'blue2'];
const numGores = 6;
const anglePer = 360 / numGores;

const gores = [];
for (let i = 0; i < numGores; i++) {
  const angle = i * anglePer;
  const halfAngle = anglePer / 2;
  // Wedge cut: intersect sphere with angular sector
  // Create a large wedge box at this angle
  const wedgeR = 20; // bigger than sphere
  const a1 = (angle - halfAngle) * Math.PI / 180;
  const a2 = (angle + halfAngle) * Math.PI / 180;
  // Build wedge from a thick pie slice using hull of points
  const pts = [
    [0, 0, -5],
    [0, 0, 45],
    [wedgeR * Math.cos(a1), wedgeR * Math.sin(a1), -5],
    [wedgeR * Math.cos(a1), wedgeR * Math.sin(a1), 45],
    [wedgeR * Math.cos(a2), wedgeR * Math.sin(a2), -5],
    [wedgeR * Math.cos(a2), wedgeR * Math.sin(a2), 45],
  ];
  const wedgeSpheres = pts.map(p => Manifold.sphere(0.01, 4).translate(p));
  const wedge = Manifold.hull(wedgeSpheres);
  const gore = baseSphere.intersect(wedge);
  gores.push(label(gore, goreColors[i]));
}

const envelope = Manifold.union(gores);

// --- Basket: box below the balloon ---
const basket = label(box([-3, -3, 5], [3, 3, 9]), 'basket');

// --- Rigging lines: 4 thin cylinders connecting basket to balloon base ---
// Lines go from basket top corners to bottom of balloon sphere
// Balloon bottom is at envCZ - envR*1.3 = 20 - 13 = 7 (approx)
// We use thin boxes to connect
function rope(x1, y1, z1, x2, y2, z2) {
  // Create a thin cylinder approximated by a hull of two small spheres
  const thick = 0.3;
  const pts2 = [
    [x1 - thick, y1 - thick, z1],
    [x1 + thick, y1 + thick, z1],
    [x2 - thick, y2 - thick, z2],
    [x2 + thick, y2 + thick, z2],
  ];
  const ss = pts2.map(p => Manifold.sphere(thick, 6).translate(p));
  return Manifold.hull(ss);
}

const ropeFL = label(rope(-2.5, -2.5, 9, -2, -2, 14), 'rope');
const ropeFR = label(rope(2.5, -2.5, 9, 2, -2, 14), 'rope');
const ropeBL = label(rope(-2.5, 2.5, 9, -2, 2, 14), 'rope');
const ropeBR = label(rope(2.5, 2.5, 9, 2, 2, 14), 'rope');

return envelope
  .add(basket)
  .add(ropeFL).add(ropeFR).add(ropeBL).add(ropeBR);
